#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int countGoodSets(int* arr, int n) {
    int count = 0;
    for (int mask = 1; mask < (1 << n); mask++) {
        int subset[n];
        int size = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                subset[size++] = arr[i];
            }
        }
        if (isGoodSet(subset, size)) {
            count++;
        }
    }
    return (count + 1) % MOD; // +1 for the empty set
}

int isGoodSet(int* subset, int size) {
    for (int i = 0; i < size - 1; i++) {
        if (subset[i + 1] % subset[i] != 0) {
            return 0;
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", countGoodSets(arr, n));
        free(arr);
    }
    return 0;
}

