#include <iostream>
#include <vector>
using namespace std;
#define MOD 1000000007

int countGoodSets(vector<int>& arr) {
    int count = 0;
    int n = arr.size();
    for (int mask = 1; mask < (1 << n); mask++) {
        vector<int> subset;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                subset.push_back(arr[i]);
            }
        }
        if (isGoodSet(subset)) {
            count++;
        }
    }
    return (count + 1) % MOD; // +1 for the empty set
}

bool isGoodSet(vector<int>& subset) {
    for (int i = 0; i < subset.size() - 1; i++) {
        if (subset[i + 1] % subset[i] != 0) {
            return false;
        }
    }
    return true;
}

