        int count = 0;
        int n = arr.length;
        for (int mask = 1; mask < (1 << n); mask++) {
            int[] subset = new int[n];
            int size = 0;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    subset[size++] = arr[i];
                }
            }
